func fetchPokemon(c *client.Client, name string) (*pokemonResource, error) {
	var p pokemonResource
	data, err := c.Get("/api/v2/pokemon/"+url.PathEscape(strings.ToLower(name))+"/", nil)
	if err != nil {
		return nil, err
	}
	return &p, json.Unmarshal(data, &p)
}

