func namesFromSlots(types []struct {
	Slot int              `json:"slot"`
	Type namedAPIResource `json:"type"`
}) []string {
	sort.Slice(types, func(i, j int) bool { return types[i].Slot < types[j].Slot })
	out := make([]string, 0, len(types))
	for _, t := range types {
		out = append(out, t.Type.Name)
	}
	return out
}

func abilityRows(p *pokemonResource) []map[string]any {
	out := make([]map[string]any, 0, len(p.Abilities))
	for _, a := range p.Abilities {
		out = append(out, map[string]any{"name": a.Ability.Name, "hidden": a.IsHidden, "slot": a.Slot})
	}
	return out
}

func statMap(p *pokemonResource) map[string]int {
	out := map[string]int{}
	for _, s := range p.Stats {
		out[s.Stat.Name] = s.BaseStat
	}
	return out
}

func firstEnglishFlavorText(s *speciesResource) string {
	for _, e := range s.FlavorTextEntries {
		if e.Language.Name == "en" {
			return strings.Join(strings.Fields(e.FlavorText), " ")
		}
	}
	return ""
}

func resourceIDFromURL(raw string) string {
	parts := strings.Split(strings.Trim(raw, "/"), "/")
	if len(parts) == 0 {
		return raw
	}
	return parts[len(parts)-1]
}

func flattenEvolutionPaths(root evolutionNode) [][]string {
	var paths [][]string
	var walk func(evolutionNode, []string)
	walk = func(n evolutionNode, path []string) {
		path = append(append([]string(nil), path...), n.Species.Name)
		if len(n.EvolvesTo) == 0 {
			paths = append(paths, path)
			return
		}
		for _, child := range n.EvolvesTo {
			walk(child, path)
		}
	}
	walk(root, nil)
	return paths
}

func flattenMoves(p *pokemonResource, method, versionGroup string) []pokemonMoveRow {
	var rows []pokemonMoveRow
	for _, m := range p.Moves {
		for _, d := range m.VersionGroupDetails {
			if method != "" && d.MoveLearnMethod.Name != method {
				continue
			}
			if versionGroup != "" && d.VersionGroup.Name != versionGroup {
				continue
			}
			rows = append(rows, pokemonMoveRow{Name: m.Move.Name, LearnMethod: d.MoveLearnMethod.Name, VersionGroup: d.VersionGroup.Name, LevelLearnedAt: d.LevelLearnedAt})
		}
	}
	sort.Slice(rows, func(i, j int) bool {
		if rows[i].LevelLearnedAt == rows[j].LevelLearnedAt {
			return rows[i].Name < rows[j].Name
		}
		return rows[i].LevelLearnedAt < rows[j].LevelLearnedAt
	})
	return rows
}

func matchupForPokemon(c *client.Client, p *pokemonResource) (map[string]any, error) {
	attack := map[string]int{}
	defense := map[string]float64{}
	for _, slot := range p.Types {
		t, err := fetchType(c, slot.Type.Name)
		if err != nil {
			return nil, err
		}
		for _, r := range t.DamageRelations.DoubleDamageTo {
			attack[r.Name] = maxInt(attack[r.Name], 2)
		}
		for _, r := range t.DamageRelations.DoubleDamageFrom {
			if defense[r.Name] == 0 {
				defense[r.Name] = 1
			}
			defense[r.Name] *= 2
		}
		for _, r := range t.DamageRelations.HalfDamageFrom {
			if defense[r.Name] == 0 {
				defense[r.Name] = 1
			}
			defense[r.Name] *= 0.5
		}
		for _, r := range t.DamageRelations.NoDamageFrom {
			defense[r.Name] = 0
		}
	}
	for _, name := range allPokemonTypes() {
		if _, ok := defense[name]; !ok {
			defense[name] = 1
		}
	}
	var weak, resist, immune []string
	for typ, mult := range defense {
		switch {
		case mult == 0:
			immune = append(immune, typ)
		case mult > 1:
			weak = append(weak, fmt.Sprintf("%s x%s", typ, trimFloat(mult)))
		case mult < 1:
			resist = append(resist, fmt.Sprintf("%s x%s", typ, trimFloat(mult)))
		}
	}
	return map[string]any{"weaknesses": sortedStrings(weak), "resistances": sortedStrings(resist), "immunities": sortedStrings(immune), "offensive_coverage": sortedKeys(attack)}, nil
}

func allPokemonTypes() []string {
	return []string{"normal", "fire", "water", "electric", "grass", "ice", "fighting", "poison", "ground", "flying", "psychic", "bug", "rock", "ghost", "dragon", "dark", "steel", "fairy"}
}
func splitCSV(s string) []string {
	parts := strings.Split(s, ",")
	out := []string{}
	for _, p := range parts {
		if t := strings.TrimSpace(p); t != "" {
			out = append(out, t)
		}
	}
	return out
}
func addCounts(m map[string]int, xs []string) {
	for _, x := range xs {
		m[strings.Fields(x)[0]]++
	}
}
func stringSlice(v any) []string { xs, _ := v.([]string); return xs }
func maxInt(a, b int) int {
	if a > b {
		return a
	}
	return b
}
func trimFloat(f float64) string {
	if f == float64(int(f)) {
		return strconv.Itoa(int(f))
	}
	return strconv.FormatFloat(f, 'f', 2, 64)
}
func sortedStrings(xs []string) []string { sort.Strings(xs); return xs }
func sortedKeys(m map[string]int) []string {
	xs := make([]string, 0, len(m))
	for k := range m {
		xs = append(xs, k)
	}
	sort.Strings(xs)
	return xs
}
func sortedCountMap(m map[string]int) []map[string]any {
	keys := sortedKeys(m)
	out := make([]map[string]any, 0, len(keys))
	for _, k := range keys {
		out = append(out, map[string]any{"type": k, "count": m[k]})
	}
	return out
}
func sortedCountsAtLeast(m map[string]int, min int) []map[string]any {
	all := sortedCountMap(m)
	out := []map[string]any{}
	for _, row := range all {
		if row["count"].(int) >= min {
			out = append(out, row)
		}
	}
	return out
}
